const postCount = items.length;
console.log(`[DEBUG] Fetch WP Posts returned ${postCount} posts`);

items.slice(0, 5).forEach((item, index) => {
  const post = item.json ?? {};
  console.log(
    `[DEBUG] Post ${index + 1}: id=${post.id} slug=${post.slug} date_gmt=${post.date_gmt}`,
  );
});

return items;

const LOOKBACK_MINUTES = 70;
const now = new Date();
const cutoffMs = now.getTime() - LOOKBACK_MINUTES * 60 * 1000;

return items
  .filter((item) => {
    const post = item.json ?? {};
    const dateGmt = post.date_gmt;

    if (!dateGmt) {
      return false;
    }

    const publishedMs = Date.parse(`${dateGmt}Z`);
    return Number.isFinite(publishedMs) && publishedMs > cutoffMs;
  })
  .map((item) => ({
    json: {
      ...(item.json ?? {}),
      detectedAtUtc: now.toISOString(),
    },
  }));

const TAG_RE = /<[^>]*>/g;
const WHITESPACE_RE = /\s+/g;
const ENTITY_MAP = {
  '&amp;': '&',
  '&lt;': '<',
  '&gt;': '>',
  '&quot;': '"',
  '&#039;': "'",
  '&nbsp;': ' ',
};

function decodeEntities(value) {
  return value.replace(/&(amp|lt|gt|quot|#039|nbsp);/g, (entity) => ENTITY_MAP[entity] ?? entity);
}

function stripHtml(value) {
  if (typeof value !== 'string' || !value) {
    return '';
  }

  const text = decodeEntities(value.replace(TAG_RE, ' '));
  return text.replace(WHITESPACE_RE, ' ').trim();
}

return items.map((item) => {
  const post = item.json ?? {};
  const embedded = post._embedded ?? {};
  const mediaItems = Array.isArray(embedded['wp:featuredmedia']) ? embedded['wp:featuredmedia'] : [];
  const featuredMedia = mediaItems[0] ?? {};
  const titleRaw = post.title;
  const excerptRaw = post.excerpt;
  const title = stripHtml(typeof titleRaw === 'object' ? titleRaw?.rendered : titleRaw);
  const excerpt = stripHtml(typeof excerptRaw === 'object' ? excerptRaw?.rendered : excerptRaw);
  const imageUrl = typeof featuredMedia === 'object' ? featuredMedia.source_url ?? null : null;

  return {
    json: {
      ...post,
      titleText: title,
      excerptText: excerpt,
      topic: title,
      content: excerpt,
      postUrl: post.link,
      imageUrl,
      hasFeaturedImage: Boolean(imageUrl),
    },
  };
});
